        "content": "{\"type\":\"code-code\",\"app_id\":\"code\",\"status\":\"finished\",\"embed_id\":\"318cb1af-c826-4e40-9e62-b5520b7a99cc\",\"filename\":\"src/App.svelte\",\"language\":\"svelte\",\"line_count\":284,\"code\":\"<script>\\n    // Initial habits state using Svelte 5 runes\\n    let habits = $state([\\n        { id: 1, name: \\\"Morning Meditation\\\", icon: \\\"🧘\\\", streak: 5 },\\n        { id: 2, name: \\\"Drink 2L Water\\\", icon: \\\"💧\\\", streak: 14 },\\n        { id: 3, name: \\\"Read 10 Pages\\\", icon: \\\"📚\\\", streak: 2 }\\n    ]);\\n    \\n    let filterText = $state(\\\"\\\");\\n    let selectedId = $state(null);\\n\\n    // Derived state for filtered habits and the selected habit\\n    let filteredHabits = $derived(habits.filter(h => \\n        h.name.toLowerCase().includes(filterText.toLowerCase())\\n    ));\\n    \\n    let selectedHabit = $derived(habits.find(h => h.id === selectedId));\\n\\n    function selectHabit(id) {\\n        selectedId = id;\\n    }\\n\\n    function waterSelected() {\\n        if (!selectedId) return;\\n        const index = habits.findIndex(h => h.id === selectedId);\\n        if (index !== -1) {\\n            // Updating the state automatically triggers a UI re-render\\n            habits[index].streak += 1;\\n        }\\n    }\\n\\n    // Helper to determine plant growth stage based on the streak\\n    function getStage(streak) {\\n        if (streak >= 15) return \\\"🌳 Thriving Tree\\\";\\n        if (streak >= 7) return \\\"🪴 Healthy Plant\\\";\\n        if (streak >= 3) return \\\"🌿 Growing Sprout\\\";\\n        return \\\"🌱 New Seed\\\";\\n    }\\n</script>\\n\\n<main class=\\\"app-container\\\">\\n    <header class=\\\"header\\\">\\n        <h1>🌱 My Habit Garden</h1>\\n        <p>Nurture your daily routines and watch them grow.</p>\\n    </header>\\n\\n    <div class=\\\"search-bar\\\">\\n        <span class=\\\"search-icon\\\">🔍</span>\\n        <input \\n            type=\\\"text\\\" \\n            bind:value={filterText} \\n            placeholder=\\\"Filter your habits...\\\" \\n        />\\n    </div>\\n\\n    <div class=\\\"garden-bed\\\">\\n        {#each filteredHabits as habit (habit.id)}\\n            <button \\n                class=\\\"habit-card {selectedId === habit.id ? 'selected' : ''}\\\"\\n                onclick={() => selectHabit(habit.id)}\\n                aria-label=\\\"Select {habit.name}\\\"\\n            >\\n                <div class=\\\"card-header\\\">\\n                    <span class=\\\"habit-icon\\\">{habit.icon}</span>\\n                    <span class=\\\"streak-badge\\\">🔥 {habit.streak}</span>\\n                </div>\\n                \\n                <h3 class=\\\"habit-name\\\">{habit.name}</h3>\\n                \\n                <div class=\\\"plant-stage\\\">\\n                    {getStage(habit.streak)}\\n                </div>\\n            </button>\\n        {/each}\\n\\n        {#if filteredHabits.length === 0}\\n            <div class=\\\"empty-state\\\">\\n                <p>No habits match \\\"{filterText}\\\".</p>\\n            </div>\\n        {/if}\\n    </div>\\n\\n    <div class=\\\"action-area\\\">\\n        <button \\n            class=\\\"water-btn\\\" \\n            disabled={!selectedId} \\n            onclick={waterSelected}\\n        >\\n            <span class=\\\"water-icon\\\">💦</span> Water Selected Habit\\n        </button>\\n        \\n        <div class=\\\"hint\\\">\\n            {#if selectedHabit}\\n                Watering <strong>{selectedHabit.name}</strong> will increase its streak and help it grow!\\n            {:else}\\n                Select a habit from the garden above to water it.\\n            {/if}\\n        </div>\\n    </div>\\n</main>\\n\\n<style>\\n    .app-container {\\n        max-width: 800px;\\n        margin: 0 auto;\\n        padding: 2rem;\\n        display: flex;\\n        flex-direction: column;\\n        gap: 2rem;\\n    }\\n\\n    .header {\\n        text-align: center;\\n    }\\n\\n    .header h1 {\\n        margin: 0;\\n        font-size: 2.5rem;\\n        color: #1e3f20;\\n    }\\n\\n    .header p {\\n        margin-top: 0.5rem;\\n        color: #4a7c59;\\n        font-size: 1.1rem;\\n    }\\n\\n    .search-bar {\\n        position: relative;\\n        max-width: 400px;\\n        margin: 0 auto;\\n        width: 100%;\\n    }\\n\\n    .search-bar input {\\n        width: 100%;\\n        padding: 1rem 1rem 1rem 3rem;\\n        border: 2px solid #c8e6c9;\\n        border-radius: 99px;\\n        font-size: 1rem;\\n        font-family: inherit;\\n        outline: none;\\n        transition: all 0.2s;\\n        box-sizing: border-box;\\n    }\\n\\n    .search-bar input:focus {\\n        border-color: #4caf50;\\n        box-shadow: 0 0 0 4px rgba(76, 175, 80, 0.1);\\n    }\\n\\n    .search-icon {\\n        position: absolute;\\n        left: 1rem;\\n        top: 50%;\\n        transform: translateY(-50%);\\n        font-size: 1.2rem;\\n        pointer-events: none;\\n    }\\n\\n    .garden-bed {\\n        display: grid;\\n        grid-template-columns: repeat(auto-fit, minmax(220px, 1fr));\\n        gap: 1.5rem;\\n        padding: 1rem 0;\\n    }\\n\\n    .habit-card {\\n        background: white;\\n        border: 3px solid transparent;\\n        border-radius: 20px;\\n        padding: 1.5rem;\\n        text-align: left;\\n        cursor: pointer;\\n        transition: all 0.2s cubic-bezier(0.175, 0.885, 0.32, 1.275);\\n        box-shadow: 0 4px 15px rgba(0, 0, 0, 0.05);\\n        font-family: inherit;\\n        display: flex;\\n        flex-direction: column;\\n        gap: 1rem;\\n    }\\n\\n    .habit-card:hover {\\n        transform: translateY(-5px);\\n        box-shadow: 0 8px 25px rgba(0, 0, 0, 0.1);\\n    }\\n\\n    .habit-card.selected {\\n        border-color: #4caf50;\\n        background: #f1f8e9;\\n        transform: translateY(-5px) scale(1.02);\\n        box-shadow: 0 10px 30px rgba(76, 175, 80, 0.2);\\n    }\\n\\n    .card-header {\\n        display: flex;\\n        justify-content: space-between;\\n        align-items: center;\\n    }\\n\\n    .habit-icon {\\n        font-size: 2.5rem;\\n    }\\n\\n    .streak-badge {\\n        background: #fff3e0;\\n        color: #e65100;\\n        padding: 0.25rem 0.75rem;\\n        border-radius: 99px;\\n        font-weight: 800;\\n        font-size: 0.9rem;\\n    }\\n\\n    .habit-card.selected .streak-badge {\\n        background: white;\\n    }\\n\\n    .habit-name {\\n        margin: 0;\\n        font-size: 1.25rem;\\n        color: #2c3e50;\\n    }\\n\\n    .plant-stage {\\n        color: #4caf50;\\n        font-weight: 600;\\n        font-size: 0.95rem;\\n    }\\n\\n    .empty-state {\\n        grid-column: 1 / -1;\\n        text-align: center;\\n        color: #7f8c8d;\\n        padding: 2rem;\\n    }\\n\\n    .action-area {\\n        display: flex;\\n        flex-direction: column;\\n        align-items: center;\\n        gap: 1rem;\\n        margin-top: 1rem;\\n    }\\n\\n    .water-btn {\\n        background: #2196f3;\\n        color: white;\\n        border: none;\\n        padding: 1rem 2.5rem;\\n        font-size: 1.2rem;\\n        font-weight: bold;\\n        border-radius: 99px;\\n        cursor: pointer;\\n        display: flex;\\n        align-items: center;\\n        gap: 0.5rem;\\n        transition: all 0.2s;\\n        box-shadow: 0 4px 15px rgba(33, 150, 243, 0.3);\\n        font-family: inherit;\\n    }\\n\\n    .water-btn:hover:not(:disabled) {\\n        background: #1976d2;\\n        transform: scale(1.05);\\n    }\\n\\n    .water-btn:active:not(:disabled) {\\n        transform: scale(0.98);\\n    }\\n\\n    .water-btn:disabled {\\n        background: #cfd8dc;\\n        color: #78909c;\\n        cursor: not-allowed;\\n        box-shadow: none;\\n        transform: none;\\n    }\\n\\n    .hint {\\n        color: #546e7a;\\n        font-size: 0.95rem;\\n        height: 1.5rem;\\n    }\\n</style>\"}",
